input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    for _ in range(n):
        grid.append(input().strip())

    # prefix[i][j] = number of 1s in grid[0..i-1][0..j-1]
    pre = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n):
        for j in range(m):
            pre[i+1][j+1] = pre[i][j+1] + pre[i+1][j] - pre[i][j] + (1 if grid[i][j]=='1' else 0)

    def rect_ones(r1,c1,r2,c2):
        if r1>r2 or c1>c2: return 0
        return pre[r2+1][c2+1]-pre[r1][c2+1]-pre[r2+1][c1]+pre[r1][c1]

    ans = float('inf')
    for r1 in range(n-4):
        for r2 in range(r1+4, n):
            # col costs: zeros in col c, rows r1+1..r2-1
            col_zero = []
            for c in range(m):
                ones = rect_ones(r1+1,c,r2-1,c)
                col_zero.append((r2-r1-1) - ones)
            # row costs: zeros in row r, cols c1+1..c2-1
            # interior ones: rows r1+1..r2-1, cols c1+1..c2-1
            for c1 in range(m-3):
                for c2 in range(c1+3, m):
                    top = rect_ones(r1,c1+1,r1,c2-1)
