                    bot = rect_ones(r2,c1+1,r2,c2-1)
                    bot_zero = (c2-c1-1) - bot
                    interior = rect_ones(r1+1,c1+1,r2-1,c2-1)
                    cost = col_zero[c1]+col_zero[c2]+top_zero+bot_zero+interior
                    if cost < ans:
                        ans = cost
    print(ans)

t = int(input())
for _ in range(t):
    solve()

